import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { FaHome, FaPlusCircle, FaBriefcase } from 'react-icons/fa';

function Navbar() {
  const location = useLocation();
  
  const isActive = (path) => {
    return location.pathname === path ? 'bg-purple-700' : '';
  };

  return (
    <nav className="bg-purple-600 text-white shadow-lg">
      <div className="container mx-auto px-4">
        <div className="flex justify-between items-center h-16">
          <Link to="/" className="flex items-center space-x-2">
            <FaBriefcase className="text-2xl" />
            <span className="font-bold text-xl">JobTracker</span>
          </Link>
          
          <div className="flex space-x-4">
            <Link
              to="/"
              className={`flex items-center space-x-1 px-3 py-2 rounded-md hover:bg-purple-700 transition ${isActive('/')}`}
            >
              <FaHome />
              <span>Dashboard</span>
            </Link>
            
            <Link
              to="/add"
              className={`flex items-center space-x-1 px-3 py-2 rounded-md hover:bg-purple-700 transition ${isActive('/add')}`}
            >
              <FaPlusCircle />
              <span>Add Job</span>
            </Link>
          </div>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
